const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Parse placements to determine ratios and platforms
  let ratios = ['9:16']; // default
  let platforms = ['meta'];

  if (d.placements) {
    const p = typeof d.placements === 'string' ? JSON.parse(d.placements) : d.placements;
    const ratioSet = new Set();
    const platSet = new Set();

    if (Array.isArray(p)) {
      for (const placement of p) {
        if (placement.included !== false) {
          if (placement.ratio) ratioSet.add(placement.ratio);
          if (placement.platform) platSet.add(placement.platform);
        }
      }
    }

    if (ratioSet.size > 0) ratios = [...ratioSet];
    if (platSet.size > 0) platforms = [...platSet];
  }

  // Determine template_id from template_name
  let template_id = 'multi-item'; // default
  const tn = (d.template_name || '').toLowerCase();
  if (tn.includes('spotlight')) template_id = 'spotlight';
  else if (tn.includes('edu') || tn.includes('education')) template_id = 'educational';
  else if (tn.includes('multi')) template_id = 'multi-item';

  results.push({
    json: {
      client_id: d.client_id,
      asset_id: d.asset_id,
      template_id: template_id,
      avatar_id: d.avatar_id || null,
      background_id: d.background_id || null,
      ratios: ratios,
      platforms: platforms,
      email: 'system@ad-pilot.ai',
      source: 'weekly_cycle',
      client_name: d.client_name
    }
  });
}

return results;

const items = $input.all();
const allData = items[0]?.json?.data || [];
const jobs = allData.map(d => ({ asset_id: d.asset_id, job_id: d.job_id, status: d.status }));

return [{
  json: {
    success: true,
    message: `Triggered video generation for ${jobs.length} assets`,
    jobs: jobs,
    triggered_at: new Date().toISOString()
  }
}];

